import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../utils/AuthContext';
import { api } from '../utils/api';
import toast from 'react-hot-toast';
import { formatBusinessDate } from '../utils/date';

export default function AdminDashboard() {
  const { user, logout } = useAuth();
  const [tab, setTab] = useState('dashboard');
  const [session, setSession] = useState(null);
  const [sessionLoading, setSessionLoading] = useState(false);
  const today = formatBusinessDate();

  const loadSession = useCallback(async () => {
    try { setSession(await api.todaySession()); } catch {}
  }, []);

  useEffect(() => { loadSession(); }, [loadSession]);

  const startDay = async () => {
    setSessionLoading(true);
    try {
      const res = await api.startDay();
      toast.success(res.message || 'Day started! Agents can now login.');
      loadSession();
    } catch (err) { toast.error(err.message); }
    finally { setSessionLoading(false); }
  };

  const closeDay = async () => {
    if (!window.confirm('Close day? This will lock all entries.')) return;
    setSessionLoading(true);
    try {
      await api.closeDay();
      toast.success('Day closed successfully');
      loadSession();
    } catch (err) { toast.error(err.message); }
    finally { setSessionLoading(false); }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)' }}>
      <div style={{
        background: 'var(--surface)', borderBottom: '1px solid var(--surface2)',
        padding: '12px 20px', display: 'flex', alignItems: 'center', justifyContent: 'space-between'
      }}>
        <div>
          <span style={{ color: 'var(--accent)', fontWeight: 'bold', letterSpacing: 2 }}>FINANCE COLLECT</span>
          <span style={{ color: 'var(--muted)', fontSize: 11, marginLeft: 8 }}>ADMIN</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          {session?.status === 'OPEN' && (
            <button onClick={closeDay} disabled={sessionLoading} className="btn-danger" style={{ padding: '8px 16px', fontSize: 13 }}>
              Close Day
            </button>
          )}
          {session?.status !== 'OPEN' && (
            <button onClick={startDay} disabled={sessionLoading} className="btn-success" style={{ padding: '8px 16px', fontSize: 13 }}>
              {session ? 'Reopen Day' : 'Start Day'}
            </button>
          )}
          {session && (
            <span className={`badge ${session.status === 'OPEN' ? 'badge-green' : 'badge-red'}`}>
              {session.status}
            </span>
          )}
          <span style={{ color: 'var(--muted)', fontSize: 12 }}>{user.name}</span>
          <button onClick={logout} style={{ padding: '6px 12px', fontSize: 12, borderRadius: 6, background: 'var(--surface2)', color: 'var(--muted)' }}>
            Logout
          </button>
        </div>
      </div>

      <div className="page" style={{ paddingTop: 20 }}>
        <div className="tabs">
          {['dashboard', 'customers', 'agents', 'duplicates', 'report'].map(t => (
            <div key={t} className={`tab ${tab === t ? 'active' : ''}`} onClick={() => setTab(t)}>
              {t.charAt(0).toUpperCase() + t.slice(1)}
            </div>
          ))}
        </div>

        {tab === 'dashboard' && <DashboardTab today={today} session={session} />}
        {tab === 'customers' && <CustomersTab />}
        {tab === 'agents' && <AgentsTab />}
        {tab === 'duplicates' && <DuplicatesTab today={today} />}
        {tab === 'report' && <ReportTab today={today} />}
      </div>
    </div>
  );
}

function DashboardTab({ today, session }) {
  const [summary, setSummary] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [exportPreviewRows, setExportPreviewRows] = useState([]);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [showExportPreview, setShowExportPreview] = useState(false);

  const loadDashboard = useCallback(() => {
    api.dateSummary(today).then(setSummary).catch(() => {});
    api.dateTransactions(today).then(setTransactions).catch(() => {});
  }, [today]);

  useEffect(() => {
    loadDashboard();

    const intervalId = window.setInterval(loadDashboard, 10000);
    const onFocus = () => loadDashboard();

    window.addEventListener('focus', onFocus);
    return () => {
      window.clearInterval(intervalId);
      window.removeEventListener('focus', onFocus);
    };
  }, [loadDashboard]);

  const totalAmount = summary.reduce((s, r) => s + parseFloat(r.total_amount || 0), 0);
  const totalCash = summary.reduce((s, r) => s + parseFloat(r.cash_amount || 0), 0);
  const totalGpay = summary.reduce((s, r) => s + parseFloat(r.gpay_amount || 0), 0);
  const totalEntries = summary.reduce((s, r) => s + r.total_entries, 0);

  const openExportPreview = async () => {
    setPreviewLoading(true);
    try {
      setExportPreviewRows(await api.exportPreview(today));
      setShowExportPreview(true);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setPreviewLoading(false);
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
        <div className="page-title">TODAY — {today}</div>
        <div style={{ display: 'flex', gap: 8 }}>
          <button onClick={loadDashboard} className="btn-secondary" style={{ padding: '8px 16px', fontSize: 13 }}>
            Refresh
          </button>
          <button onClick={openExportPreview} disabled={previewLoading} className="btn-secondary" style={{ padding: '8px 16px', fontSize: 13 }}>
          📥 Export Excel
        </button>
        </div>
      </div>

      {showExportPreview && (
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
            <div className="page-title" style={{ margin: 0 }}>Export Preview</div>
            <button onClick={() => setShowExportPreview(false)} className="btn-secondary">Close</button>
          </div>
          {exportPreviewRows.length === 0 ? (
            <div style={{ color: 'var(--muted)', fontSize: 13 }}>No rows available for this date.</div>
          ) : (
            <div style={{ overflowX: 'auto' }}>
              <table>
                <thead>
                  <tr><th>Customer ID</th><th>Name</th><th>Amount Collected</th></tr>
                </thead>
                <tbody>
                  {exportPreviewRows.map((row, index) => (
                    <tr key={`${row.customer_id}-${index}`}>
                      <td>{row.customer_id}</td>
                      <td>{row.customer_name}</td>
                      <td>â‚¹{parseFloat(row.amount_collected || 0).toFixed(2)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      <div className="stats-grid">
        <div className="stat-card">
          <div className="value">₹{totalAmount.toFixed(0)}</div>
          <div className="label">Total Collected</div>
        </div>
        <div className="stat-card">
          <div className="value">₹{totalCash.toFixed(0)}</div>
          <div className="label">Cash</div>
        </div>
        <div className="stat-card">
          <div className="value">₹{totalGpay.toFixed(0)}</div>
          <div className="label">GPay</div>
        </div>
        <div className="stat-card">
          <div className="value">{totalEntries}</div>
          <div className="label">Entries</div>
        </div>
      </div>

      <div style={{ marginBottom: 16 }}>
        <div style={{ fontSize: 13, color: 'var(--muted)', marginBottom: 8 }}>AGENT SUMMARY</div>
        {summary.length === 0 ? (
          <div style={{ color: 'var(--muted)', fontSize: 13, padding: 20, textAlign: 'center' }}>No entries yet</div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table>
              <thead>
                <tr>
                  <th>Agent</th><th>Entries</th><th>Cash</th><th>GPay</th><th>Total</th><th>Dupes</th>
                </tr>
              </thead>
              <tbody>
                {summary.map(r => (
                  <tr key={r.agent_id}>
                    <td>{r.agent_name}</td>
                    <td>{r.total_entries}</td>
                    <td>₹{parseFloat(r.cash_amount).toFixed(2)}</td>
                    <td>₹{parseFloat(r.gpay_amount).toFixed(2)}</td>
                    <td style={{ fontWeight: 'bold', color: 'var(--success)' }}>₹{parseFloat(r.total_amount).toFixed(2)}</td>
                    <td>{r.duplicates > 0 ? <span className="badge badge-yellow">{r.duplicates}</span> : '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

function CustomersTab() {
  const [customers, setCustomers] = useState([]);
  const [form, setForm] = useState({ customer_code: '', name: '', address: '', phone: '' });
  const [accountForm, setAccountForm] = useState({ loan_amount: '', interest_rate: '' });
  const [showAdd, setShowAdd] = useState(false);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [detailCustomer, setDetailCustomer] = useState(null);
  const [loadingDetails, setLoadingDetails] = useState(false);

  useEffect(() => { api.getCustomers().then(setCustomers).catch(() => {}); }, []);

  const addCustomer = async (e) => {
    e.preventDefault();
    try {
      await api.createCustomer(form);
      toast.success('Customer added');
      setForm({ customer_code: '', name: '', address: '', phone: '' });
      setShowAdd(false);
      api.getCustomers().then(setCustomers);
    } catch (err) { toast.error(err.message); }
  };

  const addAccount = async (customerId) => {
    if (!accountForm.loan_amount) return;
    try {
      await api.addAccount(customerId, accountForm);
      toast.success('Account added');
      setAccountForm({ loan_amount: '', interest_rate: '' });
      setSelectedCustomer(null);
    } catch (err) { toast.error(err.message); }
  };

  const viewCustomerDetails = async (customer) => {
    setLoadingDetails(true);
    try {
      const details = await api.getCustomerDetails(customer.id);
      setDetailCustomer(details);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoadingDetails(false);
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <div className="page-title">CUSTOMERS</div>
        <button onClick={() => setShowAdd(!showAdd)} className="btn-primary" style={{ padding: '8px 16px' }}>
          + Add Customer
        </button>
      </div>

      {showAdd && (
        <div className="card" style={{ marginBottom: 16 }}>
          <form onSubmit={addCustomer}>
            <div className="grid-2">
              <div className="form-group">
                <label>Customer Code</label>
                <input value={form.customer_code} onChange={e => setForm({ ...form, customer_code: e.target.value })} placeholder="C001" required />
              </div>
              <div className="form-group">
                <label>Name</label>
                <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Full Name" required />
              </div>
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label>Phone</label>
                <input value={form.phone} onChange={e => setForm({ ...form, phone: e.target.value })} placeholder="9876543210" />
              </div>
              <div className="form-group">
                <label>Address</label>
                <input value={form.address} onChange={e => setForm({ ...form, address: e.target.value })} placeholder="Address" />
              </div>
            </div>
            <button type="submit" className="btn-primary">Add Customer</button>
          </form>
        </div>
      )}

      {selectedCustomer && (
        <div className="card" style={{ marginBottom: 16, borderColor: 'var(--accent)' }}>
          <div style={{ marginBottom: 12 }}>Add Account for <strong>{selectedCustomer.name}</strong></div>
          <div className="grid-2">
            <div className="form-group">
              <label>Loan Amount</label>
              <input type="number" value={accountForm.loan_amount} onChange={e => setAccountForm({ ...accountForm, loan_amount: e.target.value })} />
            </div>
            <div className="form-group">
              <label>Interest Rate %</label>
              <input type="number" step="0.1" value={accountForm.interest_rate} onChange={e => setAccountForm({ ...accountForm, interest_rate: e.target.value })} />
            </div>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button onClick={() => addAccount(selectedCustomer.id)} className="btn-primary">Add Account</button>
            <button onClick={() => setSelectedCustomer(null)} className="btn-secondary">Cancel</button>
          </div>
        </div>
      )}

      {detailCustomer && (
        <div className="card" style={{ marginBottom: 16, borderColor: 'var(--success)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
            <div>
              <div className="page-title" style={{ margin: 0 }}>{detailCustomer.name}</div>
              <div style={{ fontSize: 12, color: 'var(--muted)' }}>
                {detailCustomer.customer_code} {detailCustomer.phone ? `· ${detailCustomer.phone}` : ''}
              </div>
            </div>
            <button onClick={() => setDetailCustomer(null)} className="btn-secondary">Close</button>
          </div>

          {detailCustomer.accounts.length === 0 ? (
            <div style={{ color: 'var(--muted)', fontSize: 13 }}>No accounts found for this customer.</div>
          ) : (
            detailCustomer.accounts.map(account => (
              <div key={account.id} style={{ marginBottom: 16, padding: 12, borderRadius: 10, background: 'var(--surface2)' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', gap: 12, flexWrap: 'wrap', marginBottom: 10 }}>
                  <div><strong>Account #{account.id}</strong></div>
                  <div>Loan: ₹{parseFloat(account.loan_amount || 0).toFixed(2)}</div>
                  <div>Paid: ₹{parseFloat(account.paid_amount || 0).toFixed(2)}</div>
                  <div>Balance: ₹{parseFloat(account.remaining_balance || 0).toFixed(2)}</div>
                  <div>Status: {account.status}</div>
                </div>

                <div style={{ fontSize: 12, color: 'var(--muted)', marginBottom: 8 }}>Payment entries</div>
                {account.payments.length === 0 ? (
                  <div style={{ fontSize: 12, color: 'var(--muted)' }}>No payments recorded yet.</div>
                ) : (
                  <div style={{ overflowX: 'auto' }}>
                    <table>
                      <thead>
                        <tr>
                          <th>Date</th><th>Time</th><th>Amount</th><th>Mode</th><th>Agent</th><th>Status</th>
                        </tr>
                      </thead>
                      <tbody>
                        {account.payments.map(payment => (
                          <tr key={payment.id}>
                            <td>{payment.session_date}</td>
                            <td>{new Date(payment.collected_at).toLocaleTimeString('en-IN')}</td>
                            <td>₹{parseFloat(payment.amount).toFixed(2)}</td>
                            <td>{payment.payment_mode}</td>
                            <td>{payment.agent_name}</td>
                            <td>{payment.duplicate_flag ? 'Duplicate' : 'OK'}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      )}

      <div style={{ overflowX: 'auto' }}>
        <table>
          <thead>
            <tr><th>Code</th><th>Name</th><th>Phone</th><th>Action</th></tr>
          </thead>
          <tbody>
            {customers.map(c => (
              <tr key={c.id}>
                <td><span className="badge badge-blue">{c.customer_code}</span></td>
                <td>{c.name}</td>
                <td>{c.phone || '-'}</td>
                <td>
                  <button
                    onClick={() => viewCustomerDetails(c)}
                    disabled={loadingDetails}
                    style={{ padding: '4px 10px', fontSize: 12, borderRadius: 6, background: '#163047', color: '#cfe8ff', marginRight: 8 }}
                  >
                    View Details
                  </button>
                  <button
                    onClick={() => setSelectedCustomer(c)}
                    style={{ padding: '4px 10px', fontSize: 12, borderRadius: 6, background: 'var(--surface2)', color: 'var(--text)' }}
                  >
                    + Account
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function AgentsTab() {
  const [users, setUsers] = useState([]);
  const [form, setForm] = useState({ name: '', username: '', password: '', role: 'AGENT' });
  const [showAdd, setShowAdd] = useState(false);

  useEffect(() => { api.getUsers().then(setUsers).catch(() => {}); }, []);

  const addUser = async (e) => {
    e.preventDefault();
    try {
      await api.createUser(form);
      toast.success('User created');
      setForm({ name: '', username: '', password: '', role: 'AGENT' });
      setShowAdd(false);
      api.getUsers().then(setUsers);
