              <div className="form-group">
                <label>Full Name</label>
                <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} required />
              </div>
              <div className="form-group">
                <label>Username</label>
                <input value={form.username} onChange={e => setForm({ ...form, username: e.target.value })} required />
              </div>
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label>Password</label>
                <input type="password" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required />
              </div>
              <div className="form-group">
                <label>Role</label>
                <select value={form.role} onChange={e => setForm({ ...form, role: e.target.value })}>
                  <option value="AGENT">Agent</option>
                  <option value="ADMIN">Admin</option>
                </select>
              </div>
            </div>
            <button type="submit" className="btn-primary">Create User</button>
          </form>
        </div>
      )}

      <table>
        <thead>
          <tr><th>Name</th><th>Username</th><th>Role</th><th>Status</th><th>Action</th></tr>
        </thead>
        <tbody>
          {users.map(u => (
            <tr key={u.id}>
              <td>{u.name}</td>
              <td>{u.username}</td>
              <td><span className={`badge ${u.role === 'ADMIN' ? 'badge-blue' : 'badge-green'}`}>{u.role}</span></td>
              <td><span className={`badge ${u.is_active ? 'badge-green' : 'badge-red'}`}>{u.is_active ? 'Active' : 'Inactive'}</span></td>
              <td>
                {u.role !== 'ADMIN' && (
                  <button
                    onClick={() => toggle(u.id)}
                    style={{ padding: '4px 10px', fontSize: 12, borderRadius: 6, background: u.is_active ? '#4c1d1d' : '#15532a', color: u.is_active ? 'var(--danger)' : 'var(--success)' }}
                  >
                    {u.is_active ? 'Deactivate' : 'Activate'}
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function DuplicatesTab({ today }) {
  const [dupes, setDupes] = useState([]);

  const load = () => api.duplicates(today).then(setDupes).catch(() => {});
  useEffect(() => { load(); }, [today]);

  const resolve = async (id, resolution) => {
    try {
      await api.resolveDuplicate(id, resolution);
      toast.success(`Marked as ${resolution}`);
      load();
    } catch (err) { toast.error(err.message); }
  };

  return (
    <div>
      <div className="page-title">DUPLICATE ENTRIES</div>
      {dupes.length === 0 ? (
        <div style={{ textAlign: 'center', color: 'var(--success)', padding: 40 }}>
          ✓ No duplicates today
        </div>
      ) : (
        dupes.map(d => (
          <div key={d.id} className="card" style={{ marginBottom: 12, borderLeft: '3px solid var(--warning)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
              <span className="badge badge-yellow">DUPLICATE</span>
              {d.resolved && <span className="badge badge-green">{d.resolution}</span>}
            </div>
            <div style={{ fontSize: 13 }}>
              <strong>Customer:</strong> {d.customer_name}<br />
              <strong>Agent:</strong> {d.agent_name}<br />
              <strong>Amount:</strong> ₹{parseFloat(d.amount).toFixed(2)} ({d.payment_mode})<br />
              <strong>Time:</strong> {new Date(d.collected_at).toLocaleTimeString('en-IN')}
            </div>
            <div style={{ marginTop: 8, fontSize: 12, color: 'var(--muted)' }}>
              Original: ₹{parseFloat(d.orig_amount).toFixed(2)} at {new Date(d.orig_at).toLocaleTimeString('en-IN')}
            </div>
            {!d.resolved && (
              <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                <button onClick={() => resolve(d.id, 'ACCEPTED')} className="btn-success" style={{ flex: 1, padding: '8px 0' }}>
                  Accept (Keep Both)
                </button>
                <button onClick={() => resolve(d.id, 'REJECTED')} className="btn-danger" style={{ flex: 1, padding: '8px 0' }}>
                  Reject Duplicate
                </button>
              </div>
            )}
          </div>
        ))
      )}
    </div>
  );
}

function ReportTab({ today }) {
  const [date, setDate] = useState(today);
  const [summary, setSummary] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [exportPreviewRows, setExportPreviewRows] = useState([]);
  const [previewLoading, setPreviewLoading] = useState(false);

  const load = useCallback(async () => {
    try {
      const [s, t] = await Promise.all([api.dateSummary(date), api.dateTransactions(date)]);
      setSummary(s); setTransactions(t);
    } catch {}
  }, [date]);

  useEffect(() => { load(); }, [load]);

  const loadExportPreview = async () => {
    setPreviewLoading(true);
    try {
      setExportPreviewRows(await api.exportPreview(date));
    } catch (err) {
      toast.error(err.message);
    } finally {
      setPreviewLoading(false);
    }
  };

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
        <div className="page-title" style={{ margin: 0 }}>REPORT</div>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} style={{ width: 160 }} />
        <button onClick={() => api.exportExcel(date)} className="btn-secondary" style={{ padding: '8px 16px', fontSize: 13 }}>
          📥 Excel
        </button>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="value">₹{summary.reduce((s, r) => s + parseFloat(r.total_amount || 0), 0).toFixed(0)}</div>
          <div className="label">Total</div>
        </div>
        <div className="stat-card">
          <div className="value">{summary.reduce((s, r) => s + r.total_entries, 0)}</div>
          <div className="label">Entries</div>
        </div>
        <div className="stat-card">
          <div className="value">{summary.length}</div>
          <div className="label">Agents</div>
        </div>
      </div>

      <div style={{ fontSize: 13, color: 'var(--muted)', marginBottom: 8 }}>ALL TRANSACTIONS</div>
      <div style={{ overflowX: 'auto' }}>
        <table>
          <thead>
            <tr><th>Customer</th><th>Agent</th><th>Amount</th><th>Mode</th><th>Time</th><th>Status</th></tr>
          </thead>
          <tbody>
            {transactions.map(t => (
              <tr key={t.id}>
                <td>{t.customer_name}</td>
                <td>{t.agent_name}</td>
                <td style={{ fontWeight: 'bold' }}>₹{parseFloat(t.amount).toFixed(2)}</td>
                <td>{t.payment_mode}</td>
                <td style={{ fontSize: 12 }}>{new Date(t.collected_at).toLocaleTimeString('en-IN')}</td>
                <td>{t.duplicate_flag ? <span className="badge badge-yellow">DUPE</span> : <span className="badge badge-green">OK</span>}</td>
              </tr>
            ))}
          </tbody>
        </table>
        {transactions.length === 0 && (
          <div style={{ textAlign: 'center', color: 'var(--muted)', padding: 20, fontSize: 13 }}>No transactions for this date</div>
        )}
      </div>
    </div>
  );
}
